                        variables: {
                            c2_c1: "Concentration ratio across membrane",
                            z: "Charge of ion",
                            F: "Faraday constant",
                            deltaψ: "Membrane potential (V)"
                        },
                        passiveTransport: "ΔG < 0 — ions flow down electrochemical gradient spontaneously",
                        activeTransport: "ΔG > 0 — requires coupling to ATP hydrolysis (e.g. Na⁺/K⁺-ATPase)"
